div.script:
			var datos = new Array();     

			var strXML = document.getElementById("xml").innerHTML;
			var xmlData = new NomadXML("XML");
			var objxml = new NomadXML("objxml"); 
			var propxml = new NomadXML("propxml");
			xmlData.AddText(strXML); 
		    var objROOT = new Object();

			var objROOT = toObject(xmlData.FirstChild().FirstChild().ToString());   

		 	Morris.Bar({
									 element: 'graphActCV',
									 data: objROOT.data,
									 xkey: objROOT.xkey,
									 ykeys: objROOT.ykeys,
									 labels: objROOT.labels,
  									 hideHover:true,
									 resize:true
									});

html:xslt.xsl:template:
			function Detail(poiNov) {
				var dir;

				dir = "../../../ReportViewer.aspx?";
				dir = dir + "report={#PROXY.APP#}.NucleusRH.Base.Portal_Empleado.NovedadesEmpresa_detail.GEN.GADGET";
				dir = dir + "{#CHAR.AMP#}oi_novedad=" + poiNov;
        dir = dir + "{#CHAR.AMP#}LANG={#PROXY.LANG#}";

				window.open(dir, 'Novedades', 'width=800,height=600,resizable=yes');
			}
